/**
 * Generates email-safe HTML from structured signature data.
 * The HTML structure is FIXED and matches firma.html exactly.
 * Only the data values are substituted.
 */

export interface SignatureUserData {
  fullName: string;
  department: string;
  infoLine1: string;
  infoLine2: string;
  address: string;
  phone: string;
  mobile?: string;
}

export type SignatureStyle = "classic" | "geb" | "geb-gradient";

export interface SignatureTemplateData {
  id?: string;
  name?: string;
  logoUrl: string | null;
  bannerUrl: string | null;
  showInstagram: boolean;
  showFacebook: boolean;
  showWeb: boolean;
  showLinkedin?: boolean;
  showPinterest?: boolean;
  instagramUrl: string | null;
  facebookUrl: string | null;
  webLinkUrl: string | null;
  linkedinUrl?: string | null;
  pinterestUrl?: string | null;
  websiteUrl: string | null;
  website: string | null;
  disclaimerLang: "it" | "en" | "both";
  footerIt: string | null;
  footerEn: string | null;
  ecoText: string | null;
  style?: SignatureStyle;
  logoGlowUrl?: string | null;
}

